#!/usr/bin/env bash
set -euo pipefail

MODE="$1"           # "update" or "test"
PYTHON_VERSION="$2" # e.g. "3.12"
IN_FILE="$3"        # path to requirements_X_Y.in
OUT_FILE="$4"       # path to requirements_X_Y.txt

# Locate the uv binary from Bazel runfiles.
RUNFILES="${RUNFILES_DIR:-${BASH_SOURCE[0]}.runfiles}"
ARCH="$(uname -m)"
case "${ARCH}" in
    x86_64)  UV="${RUNFILES}/uv_x86_64/uv" ;;
    aarch64) UV="${RUNFILES}/uv_aarch64/uv" ;;
    *) echo "ERROR: Unsupported architecture: ${ARCH}"; exit 1 ;;
esac

if [ ! -x "${UV}" ]; then
    echo "ERROR: Could not find uv binary at ${UV}"
    exit 1
fi

TMPFILE=$(mktemp)
trap "rm -f ${TMPFILE}" EXIT

VERSION_UNDERSCORE="${PYTHON_VERSION//./_}"
HEADER="# This file is autogenerated by uv pip compile with Python ${PYTHON_VERSION}
# by the following command:
#
#    bazel run //third_party/python:requirements_${VERSION_UNDERSCORE}.update
#"

# Use the existing lockfile as a constraint so transitive deps don't
# needlessly float to latest (matches pip-compile's default behavior).
CONSTRAINT_ARGS=()
if [ -n "${BUILD_WORKSPACE_DIRECTORY:-}" ] && [ -f "${BUILD_WORKSPACE_DIRECTORY}/${OUT_FILE}" ]; then
    CONSTRAINT_ARGS=(-c "${BUILD_WORKSPACE_DIRECTORY}/${OUT_FILE}")
elif [ -f "${OUT_FILE}" ]; then
    CONSTRAINT_ARGS=(-c "${OUT_FILE}")
fi

"${UV}" pip compile \
    --python-version "${PYTHON_VERSION}" \
    --no-header \
    --format requirements.txt \
    --no-strip-extras \
    --no-strip-markers \
    --index-strategy unsafe-best-match \
    --generate-hashes \
    --emit-index-url \
    "${CONSTRAINT_ARGS[@]}" \
    "${IN_FILE}" \
    | sed 's|#   -c .*|#   -c constraints.txt|' \
    | { echo "${HEADER}"; cat; } > "${TMPFILE}"

if [ "${MODE}" = "update" ]; then
    if [ -n "${BUILD_WORKSPACE_DIRECTORY:-}" ]; then
        cp "${TMPFILE}" "${BUILD_WORKSPACE_DIRECTORY}/${OUT_FILE}"
        echo "Updated ${BUILD_WORKSPACE_DIRECTORY}/${OUT_FILE}"
    else
        cp "${TMPFILE}" "${OUT_FILE}"
        echo "Updated ${OUT_FILE}"
    fi
elif [ "${MODE}" = "test" ]; then
    if ! diff -q "${TMPFILE}" "${OUT_FILE}" > /dev/null 2>&1; then
        echo "ERROR: ${OUT_FILE} is out of date. Run: bazel run //third_party/python:requirements_${VERSION_UNDERSCORE}.update"
        diff "${TMPFILE}" "${OUT_FILE}" || true
        exit 1
    fi
    echo "OK: ${OUT_FILE} is up to date."
fi
